input.command:
WSURL=$(curl -s --noproxy '*' http://127.0.0.1:9222/json/version | node -e "let d='';process.stdin.on('data',c=>d+=c).on('end',()=>console.log(JSON.parse(d).webSocketDebuggerUrl))")
echo "WS URL from browser: $WSURL"
node -e "
const urls = [process.argv[1], process.argv[1].replace('localhost','127.0.0.1')];
let done = 0;
for (const u of urls) {
  const ws = new WebSocket(u);
  const t = setTimeout(()=>{ console.log('TIMEOUT:', u); if(++done===urls.length) process.exit(0); ws.close(); }, 5000);
  ws.onopen = ()=>{ clearTimeout(t); console.log('OPEN OK:', u); ws.close(); if(++done===urls.length) process.exit(0); };
  ws.onerror = (e)=>{ clearTimeout(t); console.log('ERROR:', u, '-', e.message || e.type); if(++done===urls.length) process.exit(0); };
}
setTimeout(()=>process.exit(0), 12000);
" "$WSURL"

