1	// Shared types across client and server.
2	
3	export type RouteName = "全球加速" | "CF加速" | "美国直连";
4	export type Billing = "特价" | "官方";
5	export type Resolution = "512" | "1K" | "2K" | "4K";
6	export type ModelName = "Nano Banana Pro" | "Nano Banana 2" | "Nano Banana";
7	
8	export interface SettingsDefaults {
9	  model: ModelName;
10	  resolution: Resolution;
11	  billing: Billing;
12	  aspectRatio: string;
13	}
14	
15	export interface Settings {
16	  apiKey: string;
17	  route: RouteName;
18	  baseUrlOverride: string;
19	  defaults: SettingsDefaults;
20	}
21	
22	export type PublicSettings = Omit<Settings, "apiKey"> & {
23	  hasApiKey: boolean;
24	  apiKeyMasked: string;
25	};
26	
27	export type JobStatus = "running" | "success" | "failed";
28	
29	export interface JobStatusResponse {
30	  id: string;
31	  status: JobStatus;
32	  progress: number | null;
33	  images: string[]; // local media URLs
