1	"use client";
2	
3	import { AnimatePresence, motion } from "motion/react";
4	import { getAction } from "@/lib/actions";
5	import { ASPECT_RATIOS, BILLINGS, comboError, MODELS, resolutionsFor } from "@/lib/models";
6	import { useStudio } from "@/lib/store";
7	import type { Billing, ModelName, Resolution } from "@/lib/types";
8	import { cn } from "@/lib/utils";
9	import { Icon } from "./icons";
10	import { Button, Segmented, Select } from "./ui";
11	
12	export function GenerateBar() {
13	  const image = useStudio((s) => s.image);
14	  const params = useStudio((s) => s.params);
15	  const updateParams = useStudio((s) => s.updateParams);
16	  const activeActionId = useStudio((s) => s.activeActionId);
17	  const refImage = useStudio((s) => s.refImage);
18	  const cancelAction = useStudio((s) => s.cancelAction);
19	  const openUpload = useStudio((s) => s.openUpload);
20	  const phase = useStudio((s) => s.phase);
21	  const settings = useStudio((s) => s.settings);
22	  const openSettings = useStudio((s) => s.openSettings);
23	  const showToast = useStudio((s) => s.showToast);
24	  const beginSubmit = useStudio((s) => s.beginSubmit);
25	  const setJobIds = useStudio((s) => s.setJobIds);
26	  const setPhase = useStudio((s) => s.setPhase);
27	  const setError = useStudio((s) => s.setError);
28	
29	  const action = getAction(activeActionId);
30	  const busy = phase === "submitting" || phase === "running";
31	  const resOptions = resolutionsFor(params.model);
32	  const cErr = comboError(params.model, params.resolution, params.billing);
33	  const needsRefMissing = !!action?.needsRef && !refImage;
34	  const canGenerate = !!image && !!params.prompt.trim() && !cErr && !needsRefMissing && !busy;
35	
36	  function onModel(v: string) {
37	    const model = v as ModelName;
38	    const rs = resolutionsFor(model);
39	    const resolution = rs.includes(params.resolution) ? params.resolution : rs[0];
40	    let billing = params.billing;
41	    if (comboError(model, resolution, billing) && !comboError(model, resolution, "特价")) billing = "特价";
42	    updateParams({ model, resolution, billing });
43	  }
44	
45	  async function generate() {
46	    if (!image) return;
47	    if (!settings?.hasApiKey) {
48	      showToast("error", "请先在设置里填入 o1key 令牌");
49	      openSettings();
50	      return;
51	    }
52	    if (needsRefMissing) {
53	      showToast("error", action?.refLabel || "请先上传参考图");
54	      openUpload();
55	      return;
56	    }
57	    if (cErr) {
58	      showToast("error", cErr);
59	      return;
60	    }
61	    beginSubmit();
62	    try {
63	      const res = await fetch("/api/jobs", {
64	        method: "POST",
65	        headers: { "Content-Type": "application/json" },
66	        body: JSON.stringify({
67	          prompt: params.prompt,
68	          model: params.model,
69	          resolution: params.resolution,
70	          aspectRatio: params.aspectRatio,
71	          billing: params.billing,
72	          count: params.count,
73	          baseImage: image.src,
74	          refImage: refImage || undefined,
75	        }),
76	      }).then((r) => r.json());
77	
78	      if (res.error) {
79	        setError(res.error);
80	        setPhase("error");
81	        showToast("error", res.error);
82	        return;
83	      }
84	      setJobIds((res.jobs as { id: string }[]).map((j) => j.id));
85	      setPhase("running");
86	    } catch (e) {
87	      setError((e as Error).message);
88	      setPhase("error");
89	      showToast("error", "提交失败，请检查网络");
90	    }
91	  }
92	
93	  if (!image) return null;
94	
95	  return (
96	    <div className="pointer-events-none absolute inset-x-0 bottom-0 z-30 flex justify-center px-4 pb-4">
97	      <AnimatePresence>
98	        <motion.div
99	          key="genbar"
100	          initial={{ opacity: 0, y: 24 }}
101	          animate={{ opacity: 1, y: 0 }}
102	          transition={{ type: "spring", stiffness: 260, damping: 28 }}
103	          className="glass pointer-events-auto w-[min(920px,96vw)] rounded-panel p-3.5"
104	        >
105	          {/* action chip + reference */}
106	          <div className="mb-2.5 flex flex-wrap items-center gap-2">
107	            {action ? (
108	              <span className="inline-flex items-center gap-2 rounded-full bg-white/[0.06] py-1 pl-2 pr-1 text-sm">
109	                <span className="flex h-6 w-6 items-center justify-center rounded-full bg-white/10 text-accent">
110	                  <Icon name={action.icon} size={13} weight="bold" />
111	                </span>
112	                <span className="font-medium text-fg">{action.label}</span>
113	                <button
114	                  onClick={cancelAction}
115	                  className="flex h-6 w-6 items-center justify-center rounded-full text-fg-mute hover:bg-white/10 hover:text-fg"
116	                  aria-label="取消操作"
117	                >
118	                  <Icon name="X" size={13} />
119	                </button>
120	              </span>
121	            ) : (
122	              <span className="text-sm text-fg-mute">未选操作 · 点击图片选操作，或直接写提示词</span>
123	            )}
124	
125	            {action?.needsRef ? (
126	              refImage ? (
127	                <button
128	                  onClick={openUpload}
129	                  className="group inline-flex items-center gap-2 rounded-full border border-line bg-panel-2 py-1 pl-1 pr-3 text-xs text-fg-dim hover:border-line-2"
130	                  title="更换参考图"
131	                >
132	                  {/* eslint-disable-next-line @next/next/no-img-element */}
133	                  <img src={refImage} alt="参考" className="h-6 w-6 rounded-full object-cover" />
134	                  参考图
135	                  <Icon name="ArrowClockwise" size={12} className="text-fg-mute group-hover:text-fg" />
136	                </button>
137	              ) : (
138	                <button
139	                  onClick={openUpload}
140	                  className="inline-flex items-center gap-1.5 rounded-full border border-amber-400/40 bg-amber-400/10 px-3 py-1 text-xs text-accent"
141	                >
142	                  <Icon name="UploadSimple" size={13} />
143	                  补上参考图
144	                </button>
145	              )
146	            ) : null}
147	          </div>
148	
149	          {/* prompt */}
150	          <textarea
151	            value={params.prompt}
152	            onChange={(e) => updateParams({ prompt: e.target.value })}
