9	export function HistoryRail() {
10	  const history = useStudio((s) => s.history);
11	  const setHistory = useStudio((s) => s.setHistory);
12	  const close = useStudio((s) => s.toggleHistory);
13	  const useAsCanvas = useStudio((s) => s.useResultAsCanvas);
14	  const showToast = useStudio((s) => s.showToast);
15	
16	  const refresh = useCallback(async () => {
17	    try {
18	      const h = await fetch("/api/history").then((r) => r.json());
19	      setHistory(h.items || []);
20	    } catch {
21	      // ignore
22	    }
23	  }, [setHistory]);
24	
25	  useEffect(() => {
26	    refresh();
27	  }, [refresh]);
28	
29	  function pick(url: string) {
30	    const img = new Image();
31	    img.onload = () => {
32	      useAsCanvas({ src: url, width: img.naturalWidth, height: img.naturalHeight });
33	      showToast("success", "已载入画布");
34	    };
35	    img.onerror = () => useAsCanvas({ src: url, width: 1024, height: 1024 });
36	    img.src = url;
37	  }
38	
39	  async function del(name: string) {
40	    try {
41	      await fetch("/api/history", {
42	        method: "DELETE",
43	        headers: { "Content-Type": "application/json" },
44	        body: JSON.stringify({ name }),
45	      });
46	      refresh();
47	    } catch {
48	      // ignore
49	    }
50	  }
51	
52	  return (
53	    <>
54	      <motion.div
55	        initial={{ opacity: 0 }}
56	        animate={{ opacity: 1 }}
57	        exit={{ opacity: 0 }}
58	        className="fixed inset-0 z-[100] bg-black/50 backdrop-blur-sm"
59	        onClick={close}
60	      />
61	      <motion.aside
62	        initial={{ x: "100%" }}
63	        animate={{ x: 0 }}
64	        exit={{ x: "100%" }}
65	        transition={{ type: "spring", stiffness: 320, damping: 34 }}
66	        className="glass fixed inset-y-0 right-0 z-[101] flex w-[min(440px,100vw)] flex-col rounded-l-panel"
67	      >
68	        <div className="flex items-center justify-between border-b border-line px-5 py-4">
69	          <div className="flex items-center gap-2.5">
70	            <Icon name="Stack" size={18} className="text-accent" />
71	            <span className="font-medium text-fg">历史生成</span>
72	            <span className="text-xs text-fg-mute">{history.length}</span>
73	          </div>
74	          <div className="flex items-center gap-1">
75	            <button onClick={refresh} className="text-fg-mute transition-colors hover:text-fg" title="刷新">
76	              <Icon name="ArrowClockwise" size={16} />
77	            </button>
78	            <button onClick={close} className="text-fg-mute transition-colors hover:text-fg" aria-label="关闭">
79	              <Icon name="X" size={18} />
80	            </button>
81	          </div>
82	        </div>
83	
84	        <div className="flex-1 overflow-y-auto px-4 py-4">
85	          {history.length === 0 ? (
86	            <div className="flex h-full flex-col items-center justify-center gap-2 text-center text-fg-mute">
87	              <Icon name="ImageSquare" size={28} />
88	              <span className="text-sm">还没有生成记录</span>
89	            </div>
90	          ) : (
91	            <div className="grid grid-cols-2 gap-3">
92	              {history.map((it) => (
93	                <div key={it.name} className="group relative overflow-hidden rounded-control border border-line">
94	                  <button onClick={() => pick(it.url)} className="block w-full">
95	                    {/* eslint-disable-next-line @next/next/no-img-element */}
96	                    <img src={it.url} alt={it.name} className="aspect-square w-full object-cover transition group-hover:scale-[1.03]" />
