                title={a.hint}
                className={cn(pill, "pl-2 pr-4")}
              >
                <span className={ball}>
                  <Icon name={a.icon} size={16} weight="bold" />
                </span>
                <span className={label}>{a.label}</span>
              </motion.button>
            </div>
          );
        })}
      </motion.div>

      <motion.div
        variants={container}
        initial="hidden"
        animate="visible"
        exit="exit"
        className="absolute right-full top-1/2 z-30"
        style={{ marginRight: 20 }}
        onClick={(e) => e.stopPropagation()}
